     2|
     3|export function resolveContent(content: any, key: string): any {
     4|  if (!content || !key) return null
     5|  let sc = content[key]
     6|  if (!sc && key.includes('.')) sc = key.split('.').reduce((o: any, k: string) => o?.[k], content)
     7|  return sc
     8|}
     9|
    10|export function resolveImage(images: any, ref: string): string {
    11|  if (!ref || !images) return ''
    12|  if (ref.startsWith('@img:') || ref.startsWith('@src:')) {
    13|    const key = ref.startsWith('@img:') ? ref.replace('@img:', '') : ref.replace('@src:', '')
    14|    const parts = key.split('.')
    15|    let obj = images
    16|    for (const p of parts) {
    17|      if (obj?.[p]) obj = obj[p]
    18|      else return ''
    19|    }
    20|    return obj?.src || obj?.fallbackSrc || ''
    21|  }
    22|  return ref
    23|}
