    49|          {navItems.map((item, i) => (
    50|            <div key={i} style={{ position: 'relative' }}>
    51|              {(() => {
    52|                let href = item.href || '#'
    53|                // Strip existing multiclient prefix (/s/en/nexa-paraguay/)
    54|                href = href.replace(/^\/s\/[^/]+\/[^/]+/, '')
    55|                // Prepend locale prefix for internal links
    56|                if (!href.startsWith('http') && !href.startsWith('/' + currentLocale)) {
    57|                  href = '/' + currentLocale + href
    58|                }
    59|                return <a href={href} style={{ color: '#333', textDecoration: 'none', fontWeight: 500, fontSize: '0.9rem', padding: '0.25rem 0', borderBottom: item.children ? '1px dashed #ccc' : 'none' }}>
    60|                  {item.label}
    61|                </a>
    62|              })()}
    63|            </div>
    64|          ))}
    65|          {/* Language Switcher Dropdown */}
    66|          <div style={{ position: 'relative' }}>
    67|            <button
    68|              onClick={() => setLangOpen(!langOpen)}
    69|              style={{ background: '#F5F5F0', border: '1px solid #ddd', borderRadius: '6px', padding: '0.3rem 0.6rem', cursor: 'pointer', fontSize: '0.85rem', color: '#333', display: 'flex', alignItems: 'center', gap: '0.3rem' }}
