    74|                  <img src={LOCALE_FLAGS[currentLocale].flag} alt={currentLocale} style={{ width: '18px', height: '12px', borderRadius: '2px', objectFit: 'cover' }} />
    75|                  {LOCALE_FLAGS[currentLocale].label}
    76|                </span>
    77|              ) : '🌐 NL'}
    78|              <span style={{ fontSize: '0.7rem' }}>{langOpen ? '▲' : '▼'}</span>
    79|            </button>
    80|            {langOpen && (
    81|              <div style={{ position: 'absolute', top: '100%', right: 0, marginTop: '0.3rem', background: '#fff', border: '1px solid #ddd', borderRadius: '8px', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', zIndex: 200, minWidth: '100px' }}>
    82|                {Object.entries(LOCALE_FLAGS).map(([code, { label, flag }]) => (
    83|                  <button
    84|                    key={code}
    85|                    onClick={() => { setLangOpen(false); switchLocale(code); }}
    86|                    style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', width: '100%', padding: '0.5rem 0.75rem', textAlign: 'left', background: code === currentLocale ? '#F5F5F0' : 'transparent', border: 'none', cursor: 'pointer', fontSize: '0.85rem', color: '#333', fontWeight: code === currentLocale ? 700 : 400 }}
    87|                  >
    88|                    <img src={flag} alt={code} style={{ width: '18px', height: '12px', borderRadius: '2px', objectFit: 'cover' }} />
    89|                    {label}
    90|                  </button>
    91|                ))}
    92|              </div>
