     2|
     3|const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000
     4|const RATE_LIMIT_MAX = 10
     5|const ipBuckets = new Map<string, { count: number; resetAt: number }>()
     6|
     7|function getRateLimitInfo(ip: string): { allowed: boolean; remaining: number; resetAt: number } {
     8|  const now = Date.now()
     9|  const bucket = ipBuckets.get(ip)
    10|  if (!bucket || now > bucket.resetAt) {
    11|    ipBuckets.set(ip, { count: 1, resetAt: now + RATE_LIMIT_WINDOW_MS })
    12|    return { allowed: true, remaining: RATE_LIMIT_MAX - 1, resetAt: now + RATE_LIMIT_WINDOW_MS }
    13|  }
    14|  const allowed = bucket.count < RATE_LIMIT_MAX
    15|  if (allowed) bucket.count++
    16|  return { allowed, remaining: Math.max(0, RATE_LIMIT_MAX - bucket.count), resetAt: bucket.resetAt }
    17|}
    18|
    19|export async function POST(request: NextRequest) {
    20|  try {
    21|    const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || request.headers.get('x-real-ip') || 'unknown'
    22|    const { allowed, remaining, resetAt } = getRateLimitInfo(ip)
    23|    if (!allowed) {
    24|      return NextResponse.json(
    25|        { error: 'Too many requests. Try again later.', retryAfter: Math.ceil((resetAt - Date.now()) / 1000) },
    26|        { status: 429, headers: { 'Retry-After': String(Math.ceil((resetAt - Date.now()) / 1000)) } }
    27|      )
    28|    }
    29|    const body = await request.json()
    30|    console.log('[Contact]', JSON.stringify({ ip, ...body }))
    31|    return NextResponse.json({ ok: true, remaining })
    32|  } catch (err) {
    33|    return NextResponse.json({ error: String(err) }, { status: 500 })
    34|  }
